import{_ as a,c as t,o as i,ag as o}from"./chunks/framework.CgegSSb6.js";const r="/assets/start-window.DM99AXuY.png",p=JSON.parse('{"title":"The GUI","description":"","frontmatter":{},"headers":[],"relativePath":"articles/gui.md","filePath":"articles/gui.md"}'),n={name:"articles/gui.md"};function l(s,e,h,u,d,g){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="the-gui" tabindex="-1">The GUI <a class="header-anchor" href="#the-gui" aria-label="Permalink to &quot;The GUI&quot;">​</a></h1><p>The <strong>GUI</strong> is the main desktop interface for Robocode Tank Royale. It helps you:</p><ul><li>connect to local or remote servers</li><li>select bots and configure battles</li><li>watch battles live and inspect bot state</li><li>record battles and replay them later</li><li>configure GUI, server, debug, and sound settings</li></ul><p>Use this page as the entry point for the GUI documentation:</p><ul><li><a href="./gui-battle-setup.html">Setting up and starting a battle</a></li><li><a href="./gui-battle-view.html">Viewing battles and bot state</a></li><li><a href="./gui-recording-and-replay.html">Recording and replaying battles</a></li><li><a href="./gui-configuration.html">Configuring the GUI</a></li></ul><h2 id="start-window" tabindex="-1">Start window <a class="header-anchor" href="#start-window" aria-label="Permalink to &quot;Start window&quot;">​</a></h2><p>When launching the GUI, you are greeted by the start window:</p><p><img src="'+r+'" alt="Start window"></p><p>The menu bar at the top provides quick access to the main tasks, such as starting a new battle with <code>Ctrl+B</code>.</p><h2 id="starting-a-battle" tabindex="-1">Starting a battle <a class="header-anchor" href="#starting-a-battle" aria-label="Permalink to &quot;Starting a battle&quot;">​</a></h2><p>For battle setup, bot selection, booting local bots, and rule configuration, see <a href="./gui-battle-setup.html">Setting up and starting a battle</a>.</p><h2 id="viewing-the-battle" tabindex="-1">Viewing the battle <a class="header-anchor" href="#viewing-the-battle" aria-label="Permalink to &quot;Viewing the battle&quot;">​</a></h2><p>For the live arena view, battle controls, and bot inspection tools, see <a href="./gui-battle-view.html">Viewing battles and bot state</a>.</p><h2 id="recording" tabindex="-1">Recording <a class="header-anchor" href="#recording" aria-label="Permalink to &quot;Recording&quot;">​</a></h2><p>For auto-recording and replaying recorded battles, see <a href="./gui-recording-and-replay.html#recording-battles">Recording and replaying battles</a>.</p><h2 id="replaying" tabindex="-1">Replaying <a class="header-anchor" href="#replaying" aria-label="Permalink to &quot;Replaying&quot;">​</a></h2><p>For replay controls and replay file handling, see <a href="./gui-recording-and-replay.html#replaying-battles">Recording and replaying battles</a>.</p><h2 id="setup-rules" tabindex="-1">Setup Rules <a class="header-anchor" href="#setup-rules" aria-label="Permalink to &quot;Setup Rules&quot;">​</a></h2><p>For the game type selector and rule configuration dialog, see <a href="./gui-battle-setup.html#setup-rules">Setting up and starting a battle</a>.</p><h2 id="local-server-log" tabindex="-1">Local Server Log <a class="header-anchor" href="#local-server-log" aria-label="Permalink to &quot;Local Server Log&quot;">​</a></h2><p>For the local server log viewer and related server dialogs, see <a href="./gui-configuration.html#local-server-log">Configuring the GUI</a>.</p><h2 id="gui-options" tabindex="-1">GUI Options <a class="header-anchor" href="#gui-options" aria-label="Permalink to &quot;GUI Options&quot;">​</a></h2><p>For language, UI scaling, console limits, and tank color mode, see <a href="./gui-configuration.html#gui-options">Configuring the GUI</a>.</p><h2 id="server-options" tabindex="-1">Server Options <a class="header-anchor" href="#server-options" aria-label="Permalink to &quot;Server Options&quot;">​</a></h2><p>For local server settings, secrets, and remote server connections, see <a href="./gui-configuration.html#server-options">Configuring the GUI</a>.</p><h2 id="debug-options" tabindex="-1">Debug Options <a class="header-anchor" href="#debug-options" aria-label="Permalink to &quot;Debug Options&quot;">​</a></h2><p>For development and testing features such as initial bot position, see <a href="./gui-configuration.html#debug-options">Configuring the GUI</a>.</p><h2 id="sound-options" tabindex="-1">Sound Options <a class="header-anchor" href="#sound-options" aria-label="Permalink to &quot;Sound Options&quot;">​</a></h2><p>For audio settings and sound effect controls, see <a href="./gui-configuration.html#sound-options">Configuring the GUI</a>.</p><h2 id="about-box" tabindex="-1">About box <a class="header-anchor" href="#about-box" aria-label="Permalink to &quot;About box&quot;">​</a></h2><p>For version, runtime, and support information shown in the About dialog, see <a href="./gui-configuration.html#about-box">Configuring the GUI</a>.</p>',31)])])}const b=a(n,[["render",l]]);export{p as __pageData,b as default};
